type FlagValue = boolean | string | number;

interface EvaluationContext {
  userId: string;
  groups: string[];
  plan: 'free' | 'pro' | 'enterprise';
  region: string;
}

interface FlagRule {
  attribute: keyof EvaluationContext;
  includes: string[];
  value: FlagValue;
}

interface FlagDefinition {
  key: string;
  defaultValue: FlagValue;
  rules: FlagRule[];
  rolloutPercentage?: number;
  rolloutValue?: FlagValue;
}

class FeatureFlagEvaluator {
  constructor(private readonly flags: Map<string, FlagDefinition>) {}

  evaluate(key: string, context: EvaluationContext): FlagValue {
    const flag = this.flags.get(key);
    if (!flag) return false;

    for (const rule of flag.rules) {
      const actual = context[rule.attribute];
      const values = Array.isArray(actual) ? actual : [String(actual)];
      if (values.some(value => rule.includes.includes(value))) {
        return rule.value;
      }
    }

    if (flag.rolloutPercentage !== undefined && flag.rolloutValue !== undefined) {
      const bucket = this.bucket(context.userId, flag.key);
      if (bucket < flag.rolloutPercentage) return flag.rolloutValue;
    }

    return flag.defaultValue;
  }

  private bucket(actorId: string, flagKey: string): number {
    const input = actorId + ':' + flagKey;
    let hash = 0;
    for (let index = 0; index < input.length; index += 1) {
      hash = (hash * 31 + input.charCodeAt(index)) >>> 0;
    }
    return hash % 100;
  }
}

class CheckoutDecisions {
  constructor(private readonly evaluator: FeatureFlagEvaluator) {}

  useNewCheckout(context: EvaluationContext): boolean {
    return this.evaluator.evaluate('checkout.new-flow', context) === true;
  }
}

const flags = new Map<string, FlagDefinition>([
  [
    'checkout.new-flow',
    {
      key: 'checkout.new-flow',
      defaultValue: false,
      rolloutPercentage: 10,
      rolloutValue: true,
      rules: [{ attribute: 'plan', includes: ['enterprise'], value: true }]
    }
  ]
]);

const decisions = new CheckoutDecisions(new FeatureFlagEvaluator(flags));
const enabled = decisions.useNewCheckout({
  userId: 'user-123',
  groups: ['beta'],
  plan: 'pro',
  region: 'us'
});

